from pydantic import BaseModel, root_validator
from typing import List, Optional
from datetime import datetime
from fastapi.middleware.cors import CORSMiddleware
import re
import string

app = FastAPI()

origins = ["*"]
app.add_middleware(
    CORSMiddleware,
    allow_origins=origins,
    allow_credentials=True,
    allow_methods=["*"],
    allow_headers=["*"],
)

tasks = []

class Task(BaseModel):
    id: int
    title: str
    description: Optional[str] = None
    status: str = "pending"
    created_at: str

    @root_validator
    def set_id_and_created_at(cls, values):
        values["id"] = len(tasks) + 1
        values["created_at"] = datetime.now().isoformat()
        return values

@app.post("/tasks", response_model=Task)
async def create_task(task: Task):
    tasks.append(task)
    return task

def get_tasks_by_status(status: Optional[str] = None) -> List[Task]:
    return [task for task in tasks if (status is None or task.status == status)]

def get_paginated_tasks(tasks: List[Task], page: int, page_size: int) -> dict:
    start_index = (page - 1) * page_size
    end_index = start_index + page_size
    return {
        "items": tasks[start_index:end_index],
        "total": len(tasks),
        "page": page,
        "page_size": page_size,
    }

@app.get("/tasks", response_model=dict)
async def get_tasks(status: Optional[str] = None, page: int = 1, page_size: int = 10):
    filtered_tasks = get_tasks_by_status(status)
    return get_paginated_tasks(filtered_tasks, page, page_size)

def is_valid_status(status: str):
    valid_statuses = set(string.ascii_lowercase)
    return all(ch in valid_statuses for ch in status)

def validate_and_update_status(task_id: int, new_status: str):
    if not is_valid_status(new_status):
        raise HTTPException(status_code=400, detail="Invalid status")
    for task in tasks:
        if task.id == task_id:
            task.status = new_status
            return task
    raise HTTPException(status_code=404, detail="Task not found")

@app.patch("/tasks/{task_id}/status", response_model=Task)
async def update_task_status(task_id: int, new_status: str):
    return validate_and_update_status(task_id, new_status)
